queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?platform_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasPlatforms ?child ; p:hasMultimedia_Journalists ?parent . } GROUP BY ?child }
  ?child p:platform_name ?platform_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Multimedia_Journalists } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?platform_name WHERE {
  ?multimedia_journalists_platforms a :Multimedia_Journalists_Platforms .
  ?platforms a :Platforms .
  ?multimedia_journalists_platforms p:hasPlatforms ?platforms .
  ?multimedia_journalists a :Multimedia_Journalists .
  ?multimedia_journalists_platforms p:hasMultimedia_Journalists ?multimedia_journalists .
  ?multimedia_journalists p:name ?name .
  ?platforms p:platform_name ?platform_name .
} }
  collective: { SELECT ?platform_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasPlatforms ?child ; p:hasMultimedia_Journalists ?parent . } GROUP BY ?child }
  ?child p:platform_name ?platform_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Multimedia_Journalists } }
  FILTER(?nf = ?total)
} }
}
